/** Fuzzy-match a query string against the target list */
export function findTargetAccount(query: string): TargetAccount | null {
  const q = query.toLowerCase().replace(/[^a-z0-9]/g, "");
  return (
    TARGET_ACCOUNTS.find((a) => {
      const name = a.company.toLowerCase().replace(/[^a-z0-9]/g, "");
      const domain = a.website.toLowerCase().replace(/[^a-z0-9]/g, "");
      return name.includes(q) || q.includes(name) || domain.includes(q) || q.includes(domain);
    }) || null
  );
}
